  margin-bottom: 15px;
  font-size: 1.3rem;
  text-shadow: 0 0 15px var(--quasar-yellow);
}

.planet-info {
  color: var(--stellar-white);
  font-size: 1rem;
  opacity: 0.85;
}

.planet-details {
  background: rgba(10, 10, 10, 0.98);
  border-radius: 15px;
  padding: 25px;
  margin-top: 25px;
  border: 3px solid var(--quasar-yellow);
  background-image: var(--black-hole-pattern-5);
  background-size: 160px 160px;
  transition: opacity 0.6s ease;
  position: relative;
  overflow: hidden;
}

.planet-details::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 3px;
  background: linear-gradient(90deg, var(--quasar-yellow), var(--accretion-orange));
}

.planet-details h3 {
  color: var(--quasar-yellow);
  margin-bottom: 15px;
  font-size: 1.5rem;
  text-shadow: 0 0 15px var(--quasar-yellow);
}

.planet-details p {
  color: var(--stellar-white);
  line-height: 1.7;
  font-size: 1.1rem;
}

/* Enhanced animations */
@keyframes fadeInLeft {
  from {
    opacity: 0;
    transform: translateX(-30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes fadeInRight {
  from {
    opacity: 0;
    transform: translateX(30px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

@keyframes fadeInUp {
  from {
    opacity: 0;
    transform: translateY(30px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

/* Enhanced responsive design */
@media (max-width: 768px) {
  .slide-container {
    margin: 0 -15px;
    border-radius: 0;
  }

  .slide-navigation {
    padding: 15px;
  }

  .slide-content {
