// Particle system for cosmic background
class ParticleSystem {
  constructor(canvas) {
    this.canvas = canvas;
    this.ctx = canvas.getContext('2d');
    this.particles = [];
    this.init();
  }

  init() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
    this.createParticles();
    this.animate();
  }

  createParticles() {
    for (let i = 0; i < 200; i++) {
      this.particles.push({
        x: Math.random() * this.canvas.width,
        y: Math.random() * this.canvas.height,
        size: Math.random() * 2 + 1,
        speedX: (Math.random() - 0.5) * 0.5,
        speedY: (Math.random() - 0.5) * 0.5,
        opacity: Math.random() * 0.8 + 0.2
      });
    }
  }

  animate() {
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

    this.particles.forEach(particle => {
      particle.x += particle.speedX;
      particle.y += particle.speedY;

      if (particle.x < 0 || particle.x > this.canvas.width) particle.speedX *= -1;
      if (particle.y < 0 || particle.y > this.canvas.height) particle.speedY *= -1;

      this.ctx.beginPath();
      this.ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
      this.ctx.fillStyle = `rgba(255, 255, 255, ${particle.opacity})`;
      this.ctx.fill();
    });

    requestAnimationFrame(() => this.animate());
  }
}

// Black hole simulation
class BlackHoleSimulation {
  constructor() {
    this.canvas = document.createElement('canvas');
    this.ctx = this.canvas.getContext('2d');
    this.particles = [];
    this.blackHole = { x: window.innerWidth / 2, y: window.innerHeight / 2, mass: 1000 };
    this.init();
  }

  init() {
    this.canvas.width = window.innerWidth;
    this.canvas.height = window.innerHeight;
    this.createParticles();
    this.animate();
    document.body.appendChild(this.canvas);
  }

  createParticles() {
    for (let i = 0; i < 500; i++) {
      this.particles.push({
        x: Math.random() * this.canvas.width,
        y: Math.random() * this.canvas.height,
        vx: (Math.random() - 0.5) * 2,
        vy: (Math.random() - 0.5) * 2,
        size: Math.random() * 2,
        color: `hsl(${Math.random() * 60 + 340}, 100%, 50%)`
      });
    }
  }

  animate() {
    this.ctx.clearRect(0, 0, this.canvas.width, this.canvas.height);

    this.particles.forEach(particle => {
      const dx = this.blackHole.x - particle.x;
      const dy = this.blackHole.y - particle.y;
      const distance = Math.sqrt(dx * dx + dy * dy);
      const force = (this.blackHole.mass / (distance * distance)) * 0.001;

      particle.vx += (dx / distance) * force;
      particle.vy += (dy / distance) * force;

      particle.x += particle.vx;
      particle.y += particle.vy;

      this.ctx.beginPath();
      this.ctx.arc(particle.x, particle.y, particle.size, 0, Math.PI * 2);
      this.ctx.fillStyle = particle.color;
      this.ctx.fill();

      if (distance < 50) {
        particle.vx *= -0.5;
        particle.vy *= -0.5;
      }
    });

    // Draw black hole
    this.ctx.beginPath();
    this.ctx.arc(this.blackHole.x, this.blackHole.y, 50, 0, Math.PI * 2);
    this.ctx.fillStyle = 'rgba(0, 0, 0, 0.8)';
    this.ctx.fill();

    this.ctx.beginPath();
    this.ctx.arc(this.blackHole.x, this.blackHole.y, 100, 0, Math.PI * 2);
    this.ctx.strokeStyle = 'rgba(255, 107, 107, 0.5)';
    this.ctx.lineWidth = 2;
    this.ctx.stroke();

    requestAnimationFrame(() => this.animate());
  }
}

