    <!-- Enhanced animations for smooth scrolling and transitions -->
    <script>
      // Smooth scrolling for navigation links
      document.querySelectorAll('a[href^="#"]').forEach(anchor => {
        anchor.addEventListener('click', function (e) {
          e.preventDefault();
          const target = document.querySelector(this.getAttribute('href'));
          if (target) {
            target.scrollIntoView({
              behavior: 'smooth',
              block: 'start'
            });
          }
        });
      });

      // Parallax effect for sections
      window.addEventListener('scroll', () => {
        const scrolled = window.pageYOffset;
        const sections = document.querySelectorAll('.parallax-section');

        sections.forEach((section, index) => {
          const sectionTop = section.offsetTop;
          const sectionHeight = section.offsetHeight;
          const sectionMiddle = sectionTop + sectionHeight / 2;

          if (scrolled + window.innerHeight > sectionMiddle) {
            section.classList.add('visible');
          }
        });
      });

      // Navigation dots functionality
      const navDots = document.querySelectorAll('.nav-dot');
      const sections = document.querySelectorAll('.card');

      navDots.forEach((dot, index) => {
        dot.addEventListener('click', () => {
          sections[index].scrollIntoView({
            behavior: 'smooth',
            block: 'start'
          });
        });
      });

      // Update active navigation dot on scroll
      window.addEventListener('scroll', () => {
        const currentScroll = window.pageYOffset;

        sections.forEach((section, index) => {
          const sectionTop = section.offsetTop;
          const sectionHeight = section.offsetHeight;

          if (currentScroll >= sectionTop - 200 && currentScroll < sectionTop + sectionHeight - 200) {
            navDots.forEach(dot => dot.classList.remove('active'));
            navDots[index].classList.add('active');
          }
        });
      });

      // Fade-in animation for elements
      const observer = new IntersectionObserver((entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            entry.target.classList.add('visible');
          }
        });
      }, { threshold: 0.1 });

      // Observe all elements with fade-in class
      document.querySelectorAll('.fade-in').forEach((el) => {
        observer.observe(el);
      });

      // Hide scroll indicator when not needed
      const scrollIndicator = document.querySelector('.scroll-indicator');

      window.addEventListener('scroll', () => {
        if (window.pageYOffset > 100) {
          scrollIndicator.classList.remove('visible');
        } else {
          scrollIndicator.classList.add('visible');
        }
      });
    </script>
